import React from 'react';
import './App.css';

function Login({ onLogin }) {
  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-icon">🏥</div>
        <h1>Hospital Management System</h1>
        <p className="login-subtitle">Select your role to continue</p>

        <div className="login-buttons">
          <button className="login-btn admin-btn" onClick={() => onLogin('Admin')}>
            Login as Admin
          </button>
          <button className="login-btn receptionist-btn" onClick={() => onLogin('Receptionist')}>
            Login as Receptionist
          </button>
          <button className="login-btn doctor-btn" onClick={() => onLogin('Doctor')}>
            Login as Doctor
          </button>
        </div>
      </div>
    </div>
  );
}

export default Login;
